SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT TRIM(s.SERVICE_ID) AS serviceId, s.SERVICE_NAME AS serviceName, s.SERVICE_DESC AS serviceDesc, s.CLASS_NAME AS className, s.METHOD_NAME AS methodName, s.SERVICE_TYPE AS serviceType, s.BIZ_GROUP_ID AS bizGroupId, s.ORG_ID AS orgId, s.IO_TYPE AS ioType, s.WORK_SPACE_ID AS workSpaceId, s.TRX_ID AS trxId, s.USE_YN AS useYn, s.PRE_PROCESS_APP_ID AS preProcessAppId, s.POST_PROCESS_APP_ID AS postProcessAppId, s.TIME_CHECK_YN AS timeCheckYn, s.START_TIME AS startTime, s.END_TIME AS endTime, s.BIZDAY_SERVICE_YN AS bizdayServiceYn, s.BIZDAY_SERVICE_START_TIME AS bizdayStartTime, s.BIZDAY_SERVICE_END_TIME AS bizdayEndTime, s.SATURDAY_SERVICE_YN AS saturdayServiceYn, s.SATURDAY_SERVICE_START_TIME AS saturdayStartTime, s.SATURDAY_SERVICE_END_TIME AS saturdayEndTime, s.HOLIDAY_SERVICE_YN AS holidayServiceYn, s.HOLIDAY_SERVICE_START_TIME AS holidayStartTime, s.HOLIDAY_SERVICE_END_TIME AS holidayEndTime, s.LOGIN_ONLY_YN AS loginOnlyYn, s.SECURE_SIGN_YN AS secureSignYn, s.REQ_CHANNEL_CODE AS reqChannelCode, s.BANK_STATUS_CHECK_YN AS bankStatusCheckYn, s.BANK_CODE_FIELD AS bankCodeField, s.LAST_UPDATE_DTIME AS lastUpdateDtime, TRIM(s.LAST_UPDATE_USER_ID) AS lastUpdateUserId, (SELECT COUNT(*) FROM FWK_SERVICE_RELATION sr2 WHERE sr2.SERVICE_ID = s.SERVICE_ID) AS componentCount, (SELECT COUNT(*) FROM FWK_ACCESS_USER au WHERE au.GUBUN_TYPE = 'S' AND au.TRX_ID = s.SERVICE_ID) AS accessUserCount FROM FWK_SERVICE s
ORDER BY
s.SERVICE_NAME s.SERVICE_TYPE s.USE_YN s.LAST_UPDATE_DTIME s.SERVICE_ID
DESC ASC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}

SELECT * FROM (
    SELECT A.*, ROWNUM AS RNUM FROM (
        SELECT
            WORK_SPACE_ID   AS workSpaceId,
            WORK_SPACE_NAME AS workSpaceName,
            THREAD_COUNT    AS threadCount
        FROM FWK_WORK_SPACE


                AND WORK_SPACE_ID LIKE '%' || #{workSpaceId} || '%'


                AND WORK_SPACE_NAME LIKE '%' || #{workSpaceName} || '%'


        ORDER BY WORK_SPACE_ID
    ) A
    WHERE ROWNUM <= #{offset} + #{limit}
) WHERE RNUM > #{offset}
